(function () {
  "use strict";

  /* ── Admin auth ── */
  var ADMIN_USERNAME = "admin";
  var ADMIN_PASSWORD_HASH =
    "28b5ac77a74654a8f388c1961226883e2e4f1de12c31624a476e34fe59e3e4c3";
  var ADMIN_RECOVERY_PASSWORD_HASH =
    "a36aef5a11c4073fbe60314fc9df530a9d5f986533594d1f5190742ff9e0e408";

  function sha256Hex(text) {
    return crypto.subtle
      .digest("SHA-256", new TextEncoder().encode(text))
      .then(function (buf) {
        return [...new Uint8Array(buf)]
          .map(function (b) {
            return b.toString(16).padStart(2, "0");
          })
          .join("");
      });
  }

  var loginGate = document.getElementById("login-gate");
  var sessionBar = document.getElementById("session-bar");
  var panelContent = document.getElementById("panel-content");
  var loginForm = document.getElementById("login-form");
  var loginError = document.getElementById("login-error");

  function showUnlocked(u) {
    loginGate.style.display = "none";
    sessionBar.style.display = "flex";
    panelContent.style.display = "block";
    document.getElementById("session-user").textContent = u;
  }
  function showLocked() {
    loginGate.style.display = "block";
    sessionBar.style.display = "none";
    panelContent.style.display = "none";
    loginForm.reset();
    loginError.textContent = "";
    document.getElementById("forgot-hint").hidden = true;
  }

  loginForm.addEventListener("submit", function (e) {
    e.preventDefault();
    var u = document.getElementById("login-username").value.trim();
    var p = document.getElementById("login-password").value;
    var btn = loginForm.querySelector(".login-btn");
    btn.disabled = true;
    sha256Hex(p)
      .then(function (hash) {
        btn.disabled = false;
        if (
          u === ADMIN_USERNAME &&
          (hash === ADMIN_PASSWORD_HASH ||
            hash === ADMIN_RECOVERY_PASSWORD_HASH)
        ) {
          loginError.textContent = "";
          showUnlocked(u);
        } else {
          loginError.textContent = "Incorrect username or password.";
        }
      })
      .catch(function () {
        btn.disabled = false;
        loginError.textContent = "Could not verify in this browser.";
      });
  });
  document.getElementById("logout-btn").addEventListener("click", showLocked);
  document.getElementById("forgot-link").addEventListener("click", function () {
    var h = document.getElementById("forgot-hint");
    h.hidden = !h.hidden;
  });
  showLocked();

  /* ── Fixtures persistence (this browser only) ──
     Fixtures are saved to localStorage every time they're added, edited,
     or removed, and reloaded on the next visit so the poster always
     reflects the latest saved fixture list instead of resetting to the
     hardcoded defaults. */
  var FIXTURES_STORAGE_KEY = "kipl_poster_fixtures_v1";
  var DEFAULT_FIXTURES = [
    { team1: "Sky Riders", team2: "Royal Elevens", ground: "Sky" },
    { team1: "Blinks", team2: "V Tamiln's", ground: "Chennai" },
    { team1: "Rayyan Warriors", team2: "MCC", ground: "Blinks" },
    { team1: "FFC", team2: "My Elevens", ground: "FFC" },
  ];

  function loadSavedFixtures() {
    try {
      var raw = window.localStorage.getItem(FIXTURES_STORAGE_KEY);
      if (!raw) return null;
      var parsed = JSON.parse(raw);
      if (Array.isArray(parsed) && parsed.length) return parsed;
      return null;
    } catch (e) {
      console.warn("Could not read saved fixtures:", e);
      return null;
    }
  }

  function saveFixtures() {
    try {
      window.localStorage.setItem(
        FIXTURES_STORAGE_KEY,
        JSON.stringify(state.fixtures),
      );
      flashFixturesSaved();
    } catch (e) {
      console.warn("Could not save fixtures:", e);
    }
  }

  function flashFixturesSaved() {
    var el = document.getElementById("fixtures-save-status");
    if (!el) return;
    el.textContent = "Saved ✓ (this browser)";
    el.classList.add("is-visible");
    window.clearTimeout(flashFixturesSaved._t);
    flashFixturesSaved._t = window.setTimeout(function () {
      el.classList.remove("is-visible");
    }, 1600);
  }

  /* ── State ── */
  var state = {
    fixtures: loadSavedFixtures() || DEFAULT_FIXTURES.slice(),
    logoLeft: null, // HTMLImageObject when loaded
    logoRight: null,
  };

  /* ── Logo canvas rendering ──
     We draw the uploaded image onto a <canvas> clipped to a circle.
     This works identically on screen and in html2canvas export. */
  function drawCircularLogo(canvasEl, imgObj) {
    var SIZE = 144; // 72px display × 2 for sharpness
    canvasEl.width = SIZE;
    canvasEl.height = SIZE;
    var ctx = canvasEl.getContext("2d");
    ctx.clearRect(0, 0, SIZE, SIZE);
    // Clip to circle
    ctx.beginPath();
    ctx.arc(SIZE / 2, SIZE / 2, SIZE / 2, 0, Math.PI * 2);
    ctx.closePath();
    ctx.clip();
    // White background so transparent PNG areas look clean
    ctx.fillStyle = "#ffffff";
    ctx.fillRect(0, 0, SIZE, SIZE);
    // Draw image fitting the full circle
    ctx.drawImage(imgObj, 0, 0, SIZE, SIZE);
  }

  function loadLogoIntoCanvas(file, canvasId, fallbackId) {
    if (!file) return;
    var img = new Image();
    var reader = new FileReader();
    reader.onload = function (ev) {
      img.onload = function () {
        var cv = document.getElementById(canvasId);
        drawCircularLogo(cv, img);
        cv.style.display = "block";
        document.getElementById(fallbackId).style.display = "none";
        // Store for re-draw if needed
        if (canvasId === "logoLeftCanvas") state.logoLeft = img;
        if (canvasId === "logoRightCanvas") state.logoRight = img;
      };
      img.src = ev.target.result;
    };
    reader.readAsDataURL(file);
  }

  /* ── Pre-load default badges ──
     These are embedded as base64 data URIs (instead of loaded from
     ktic1.png / rw.png as separate files) so they never taint the
     canvas. Loading images from a file:// path or any URL without
     proper CORS headers marks the canvas as "tainted", which makes
     canvas.toDataURL() throw a SecurityError during export — that is
     what produces the "Could not render" message. Data URIs avoid
     that entirely, regardless of how this page is hosted/opened. */
  var DEFAULT_LOGO_LEFT_SRC =
    "data:image/png;base64,";
  var DEFAULT_LOGO_RIGHT_SRC =
    "data:image/png;base64,";

  (function () {
    var img = new Image();
    img.onload = function () {
      var cv = document.getElementById("logoLeftCanvas");
      if (cv) {
        drawCircularLogo(cv, img);
        cv.style.display = "block";
      }
      var fb = document.getElementById("logoLeftFallback");
      if (fb) fb.style.display = "none";
      state.logoLeft = img;
    };
    img.src = DEFAULT_LOGO_LEFT_SRC;
  })();

  (function () {
    var img = new Image();
    img.onload = function () {
      var cv = document.getElementById("logoRightCanvas");
      if (cv) {
        drawCircularLogo(cv, img);
        cv.style.display = "block";
      }
      var fb = document.getElementById("logoRightFallback");
      if (fb) fb.style.display = "none";
      state.logoRight = img;
    };
    img.src = DEFAULT_LOGO_RIGHT_SRC;
  })();

  document
    .getElementById("upload-left")
    .addEventListener("change", function (e) {
      loadLogoIntoCanvas(
        e.target.files && e.target.files[0],
        "logoLeftCanvas",
        "logoLeftFallback",
      );
    });
  document
    .getElementById("upload-right")
    .addEventListener("change", function (e) {
      loadLogoIntoCanvas(
        e.target.files && e.target.files[0],
        "logoRightCanvas",
        "logoRightFallback",
      );
    });

  /* ── Text bindings (Header + Schedule) ──
     Saved to localStorage on every change and restored on load, the
     same way fixtures are, so the poster always reflects what you
     last typed instead of resetting to the hardcoded HTML defaults. */
  var POSTER_TEXT_STORAGE_KEY = "kipl_poster_text_v1";
  var TEXT_FIELDS = [
    { input: "in-presents", output: "out-presents" },
    { input: "in-headline", output: "out-headline" },
    { input: "in-tagline", output: "out-tagline" },
    { input: "in-date", output: "out-date" },
    { input: "in-matchlabel", output: "out-matchlabel" },
    { input: "in-time", output: "out-time" },
  ];

  function applyHeadlineExtras(value) {
    var v = value || "K-TIC";
    var wm = document.getElementById("out-watermark");
    if (wm) wm.textContent = v;
    var fb = document.getElementById("logoLeftFallback");
    if (fb) fb.textContent = v.charAt(0).toUpperCase() || "K";
  }

  function loadSavedTextFields() {
    try {
      var raw = window.localStorage.getItem(POSTER_TEXT_STORAGE_KEY);
      if (!raw) return null;
      var parsed = JSON.parse(raw);
      if (parsed && typeof parsed === "object") return parsed;
      return null;
    } catch (e) {
      console.warn("Could not read saved header/schedule text:", e);
      return null;
    }
  }

  function saveTextFields() {
    try {
      var data = {};
      TEXT_FIELDS.forEach(function (f) {
        var inp = document.getElementById(f.input);
        if (inp) data[f.input] = inp.value;
      });
      window.localStorage.setItem(
        POSTER_TEXT_STORAGE_KEY,
        JSON.stringify(data),
      );
    } catch (e) {
      console.warn("Could not save header/schedule text:", e);
    }
  }

  function applySavedTextFields() {
    var saved = loadSavedTextFields();
    if (!saved) return;
    TEXT_FIELDS.forEach(function (f) {
      if (Object.prototype.hasOwnProperty.call(saved, f.input)) {
        var inp = document.getElementById(f.input);
        var out = document.getElementById(f.output);
        if (inp) inp.value = saved[f.input];
        if (out) out.textContent = saved[f.input];
      }
    });
    if (Object.prototype.hasOwnProperty.call(saved, "in-headline")) {
      applyHeadlineExtras(saved["in-headline"]);
    }
  }
  applySavedTextFields();

  function bindText(inputId, outId) {
    var inp = document.getElementById(inputId);
    var out = document.getElementById(outId);
    inp.addEventListener("input", function () {
      out.textContent = inp.value;
      saveTextFields();
    });
  }
  TEXT_FIELDS.forEach(function (f) {
    bindText(f.input, f.output);
  });

  document
    .getElementById("in-headline")
    .addEventListener("input", function (e) {
      applyHeadlineExtras(e.target.value);
    });

  /* ── Fixtures ── */
  function buildPosterFixtureRow(f, i) {
    var row = document.createElement("div");
    row.className = "fixture-row " + (i % 2 === 0 ? "alt-a" : "alt-b");
    var teams = document.createElement("div");
    teams.className = "fixture-teams";
    var t1 = document.createElement("span");
    t1.className = "team team-a";
    t1.textContent = f.team1 || "Team A";
    var vs = document.createElement("span");
    vs.className = "vs-badge";
    vs.textContent = "VS";
    var t2 = document.createElement("span");
    t2.className = "team team-b";
    t2.textContent = f.team2 || "Team B";
    teams.appendChild(t1);
    teams.appendChild(vs);
    teams.appendChild(t2);
    var ground = document.createElement("div");
    ground.className = "fixture-ground";
    ground.textContent = "Ground - " + (f.ground || "TBD");
    row.appendChild(teams);
    row.appendChild(ground);
    return row;
  }
  function renderPosterFixtures() {
    var wrap = document.getElementById("out-fixtures");
    wrap.replaceChildren();
    if (!state.fixtures.length) {
      var e = document.createElement("div");
      e.className = "fixtures-empty";
      e.textContent = "Add a fixture to see it here.";
      wrap.appendChild(e);
      return;
    }
    state.fixtures.forEach(function (f, i) {
      wrap.appendChild(buildPosterFixtureRow(f, i));
    });
  }
  function updateFixtureCount() {
    var n = state.fixtures.length;
    document.getElementById("fixture-count").textContent =
      n + (n === 1 ? " FIXTURE SET" : " FIXTURES SET");
  }
  function makeLabeledInput(label, val, cb, onBlur) {
    var l = document.createElement("label");
    l.className = "field";
    var s = document.createElement("span");
    s.textContent = label;
    var inp = document.createElement("input");
    inp.type = "text";
    inp.value = val;
    inp.addEventListener("input", function (e) {
      cb(e.target.value);
    });
    if (onBlur) {
      inp.addEventListener("blur", onBlur);
    }
    l.appendChild(s);
    l.appendChild(inp);
    return l;
  }
  /* ── Duplicate fixture detection ──
     Two fixtures are considered duplicates if they have the same pair of
     teams (regardless of which is team1/team2) and the same ground,
     compared case-insensitively after trimming whitespace. */
  function fixtureKey(f) {
    var a = (f.team1 || "").trim().toLowerCase();
    var b = (f.team2 || "").trim().toLowerCase();
    var g = (f.ground || "").trim().toLowerCase();
    var teams = [a, b].sort();
    return teams[0] + "|" + teams[1] + "::" + g;
  }

  function getDuplicateIndices() {
    var seen = {};
    var dup = new Set();
    state.fixtures.forEach(function (f, i) {
      var key = fixtureKey(f);
      if (!seen[key]) seen[key] = [];
      seen[key].push(i);
    });
    Object.keys(seen).forEach(function (key) {
      if (seen[key].length > 1) {
        seen[key].forEach(function (i) {
          dup.add(i);
        });
      }
    });
    return dup;
  }

  function updateDuplicateHighlighting() {
    var dupSet = getDuplicateIndices();
    var rows = document.querySelectorAll("#fixture-editor .fixture-edit-row");
    rows.forEach(function (row, i) {
      var badge = row.querySelector(".dup-badge");
      if (dupSet.has(i)) {
        row.classList.add("is-duplicate");
        if (badge) badge.hidden = false;
      } else {
        row.classList.remove("is-duplicate");
        if (badge) badge.hidden = true;
      }
    });
    return dupSet;
  }

  var duplicateToastTimer = null;
  function showDuplicateToast(message) {
    var toast = document.getElementById("duplicate-toast");
    var text = document.getElementById("duplicate-toast-text");
    if (!toast || !text) return;
    text.textContent = message;
    toast.classList.add("is-visible");
    window.clearTimeout(duplicateToastTimer);
    duplicateToastTimer = window.setTimeout(function () {
      toast.classList.remove("is-visible");
    }, 5000);
  }
  function hideDuplicateToast() {
    var toast = document.getElementById("duplicate-toast");
    if (!toast) return;
    toast.classList.remove("is-visible");
    window.clearTimeout(duplicateToastTimer);
  }
  function checkDuplicatesAndNotify(showPopup) {
    var dupSet = updateDuplicateHighlighting();
    if (showPopup && dupSet.size > 0) {
      showDuplicateToast(
        "Duplicate fixture detected — two or more fixtures have the same teams and ground. Please make each fixture unique.",
      );
    } else if (dupSet.size === 0) {
      hideDuplicateToast();
    }
    return dupSet;
  }
  var duplicateToastCloseBtn = document.getElementById("duplicate-toast-close");
  if (duplicateToastCloseBtn) {
    duplicateToastCloseBtn.addEventListener("click", hideDuplicateToast);
  }

  function renderFixtureEditor() {
    var wrap = document.getElementById("fixture-editor");
    wrap.replaceChildren();
    var dupSet = getDuplicateIndices();
    state.fixtures.forEach(function (f, i) {
      var card = document.createElement("div");
      card.className = "fixture-edit-row" + (dupSet.has(i) ? " is-duplicate" : "");
      var top = document.createElement("div");
      top.className = "row-top";
      var titleWrap = document.createElement("span");
      titleWrap.className = "row-title";
      var strong = document.createElement("strong");
      strong.textContent = "Fixture " + (i + 1);
      var badge = document.createElement("span");
      badge.className = "dup-badge";
      badge.textContent = "⚠ Duplicate";
      badge.hidden = !dupSet.has(i);
      titleWrap.appendChild(strong);
      titleWrap.appendChild(badge);
      var rm = document.createElement("button");
      rm.type = "button";
      rm.className = "remove-btn";
      rm.textContent = "Remove";
      rm.addEventListener("click", function () {
        state.fixtures.splice(i, 1);
        renderFixtureEditor();
        renderPosterFixtures();
        updateFixtureCount();
        saveFixtures();
        checkDuplicatesAndNotify(true);
      });
      top.appendChild(titleWrap);
      top.appendChild(rm);
      card.appendChild(top);
      var two = document.createElement("div");
      two.className = "two-col";
      two.appendChild(
        makeLabeledInput(
          "Team 1",
          f.team1,
          function (v) {
            f.team1 = v;
            renderPosterFixtures();
            saveFixtures();
            updateDuplicateHighlighting();
          },
          function () {
            checkDuplicatesAndNotify(true);
          },
        ),
      );
      two.appendChild(
        makeLabeledInput(
          "Team 2",
          f.team2,
          function (v) {
            f.team2 = v;
            renderPosterFixtures();
            saveFixtures();
            updateDuplicateHighlighting();
          },
          function () {
            checkDuplicatesAndNotify(true);
          },
        ),
      );
      card.appendChild(two);
      card.appendChild(
        makeLabeledInput(
          "Ground",
          f.ground,
          function (v) {
            f.ground = v;
            renderPosterFixtures();
            saveFixtures();
            updateDuplicateHighlighting();
          },
          function () {
            checkDuplicatesAndNotify(true);
          },
        ),
      );
      wrap.appendChild(card);
    });
  }
  document.getElementById("add-fixture").addEventListener("click", function () {
    state.fixtures.push({ team1: "Team A", team2: "Team B", ground: "TBD" });
    renderFixtureEditor();
    renderPosterFixtures();
    updateFixtureCount();
    saveFixtures();
    checkDuplicatesAndNotify(true);
  });
  var resetFixturesBtn = document.getElementById("reset-fixtures");
  if (resetFixturesBtn) {
    resetFixturesBtn.addEventListener("click", function () {
      state.fixtures = DEFAULT_FIXTURES.slice().map(function (f) {
        return { team1: f.team1, team2: f.team2, ground: f.ground };
      });
      renderFixtureEditor();
      renderPosterFixtures();
      updateFixtureCount();
      hideDuplicateToast();
      try {
        window.localStorage.removeItem(FIXTURES_STORAGE_KEY);
      } catch (e) {
        console.warn("Could not clear saved fixtures:", e);
      }
    });
  }
  renderFixtureEditor();
  renderPosterFixtures();
  updateFixtureCount();
  checkDuplicatesAndNotify(true);

  /* ── Colors ── */
  function bindColor(id, cssVar) {
    document.getElementById(id).addEventListener("input", function (e) {
      document.documentElement.style.setProperty(cssVar, e.target.value);
    });
  }
  bindColor("color-accent", "--lime");
  bindColor("color-panel", "--forest-mid");
  bindColor("color-bg", "--forest-dark");
  bindColor("color-gold", "--gold");

  /* ── Export ── */
  document
    .getElementById("download-btn")
    .addEventListener("click", function () {
      var status = document.getElementById("download-status");
      status.textContent = "Rendering image…";
      var node = document.getElementById("poster");

      html2canvas(node, {
        scale: 2,
        useCORS: true,
        allowTaint: true,
        backgroundColor: "#0f2a0a",
        logging: false,
        onclone: function (clonedDoc, clonedEl) {
          /* 1. Re-draw circular logos in the clone using stored image objects */
          ["Left", "Right"].forEach(function (side) {
            var imgObj = state["logo" + side];
            var cv = clonedDoc.getElementById("logo" + side + "Canvas");
            var fb = clonedDoc.getElementById("logo" + side + "Fallback");
            if (imgObj && cv) {
              drawCircularLogo(cv, imgObj);
              cv.style.display = "block";
              if (fb) fb.style.display = "none";
            }
          });

          /* 2. Flatten unsupported CSS for html2canvas */
          var fix = clonedDoc.createElement("style");
          fix.textContent = [
            ".headline{",
            "  background:none !important;",
            "  -webkit-background-clip:unset !important;",
            "  background-clip:unset !important;",
            "  color:#4cd400 !important;",
            "  text-shadow:none !important;",
            "  -webkit-text-stroke:3px #1a6600 !important;",
            "  animation:none !important;",
            "}",
            ".presents{",
            "  background:none !important;",
            "  -webkit-background-clip:unset !important;",
            "  background-clip:unset !important;",
            "  color:#ffb648 !important;",
            "}",
            ".poster{",
            "  background:linear-gradient(165deg,#163a0f,#0f2a0a 70%) !important;",
            "}",
          ].join("\n");
          clonedDoc.head.appendChild(fix);
        },
      })
        .then(function (canvas) {
          var link = document.createElement("a");
          var name = (document.getElementById("in-headline").value || "poster")
            .trim()
            .replace(/\s+/g, "-");
          link.download = name + "-poster.jpeg";
          link.href = canvas.toDataURL("image/jpeg", 0.92);
          link.click();
          status.textContent = "Downloaded ✓";
        })
        .catch(function (err) {
          console.error("Export error:", err);
          var detail = err && err.message ? err.message : String(err);
          status.textContent = "Could not render (" + detail + ") — try again, or a different browser.";
        });
    });
})();
